export const toolFaqEs: Record<string, FAQItem[]> = {
  "merge": [
    { question: "¿Cómo combino varios PDF en un solo archivo?", answer: "Agrega los archivos PDF que quieras combinar y luego arrástralos en el orden que prefieras. Una vez organizados, la herramienta los une en un único documento conservando las fuentes, el diseño y el formato originales de cada archivo. Descarga el resultado combinado al instante." },
    { question: "¿Puedo reordenar los PDF antes de combinarlos?", answer: "Sí. Antes de combinarlos, puedes arrastrar cada archivo a la secuencia que prefieras para que el documento final siga exactamente el orden que deseas. Esto resulta útil al consolidar capítulos, facturas o contratos que deben aparecer en una disposición específica." },
    { question: "¿Hay un límite de cuántos PDF puedo combinar?", answer: "Puedes combinar tantos archivos PDF como necesites en un solo documento. Como todo se ejecuta localmente en tu navegador usando la memoria de tu propio dispositivo, los lotes muy grandes dependen de los recursos disponibles de tu equipo en lugar de un límite fijo del servidor." },
    { question: "¿Se suben mis archivos a algún lugar cuando los combino?", answer: "No. Toda la combinación ocurre directamente en tu navegador, por lo que tus PDF nunca salen de tu dispositivo ni pasan por un servidor. Esto mantiene los documentos sensibles, como contratos e informes financieros, completamente privados y confidenciales durante todo el proceso." },
    { question: "¿La herramienta Combinar PDF es gratuita?", answer: "Totalmente gratuita, sin registro ni cuenta. Puedes combinar PDF ilimitados tantas veces como quieras sin costo, y no se agregan marcas de agua a tu documento combinado." },
  ],
  "split": [
    { question: "¿Cómo divido un PDF en archivos separados?", answer: "Carga tu PDF y elige un método de división: rangos de páginas personalizados, una cantidad fija de páginas o dividir cada N páginas. La herramienta divide el documento en archivos más pequeños al instante, conservando cada uno el texto, las imágenes y la calidad de formato originales." },
    { question: "¿Qué métodos de división admite esta herramienta?", answer: "Puedes dividir por rangos de páginas personalizados para extraer secciones específicas, por un número fijo de páginas por archivo o cada N páginas. Esta flexibilidad te permite separar un informe largo en capítulos o extraer exactamente las páginas que necesitas." },
    { question: "¿Dividir me ayuda a cumplir con los límites de tamaño de los adjuntos de correo?", answer: "Sí. Dividir un PDF grande en archivos más pequeños es una forma común de ajustar los documentos a las restricciones de tamaño de correo o subida. Divide el archivo en partes manejables y luego envía cada parte por separado sin perder calidad." },
    { question: "¿Dividir reducirá la calidad de mi PDF?", answer: "No. Cada archivo resultante conserva la misma claridad de texto, imágenes y formato que el PDF original. La operación de división simplemente separa las páginas en lugar de recomprimirlas, por lo que cada resultado coincide con la calidad del documento original." },
    { question: "¿Se suben mis documentos cuando divido un PDF?", answer: "Nunca. Toda la división se ejecuta dentro de tu navegador, por lo que tu archivo permanece en tu dispositivo todo el tiempo. No se envía nada a un servidor, lo que mantiene el material confidencial o sensible totalmente privado." },
  ],
  "delete-pages": [
    { question: "¿Cómo elimino páginas de un PDF?", answer: "Selecciona las páginas que quieras quitar y la herramienta crea un nuevo PDF sin ellas, dejando intacto el resto de tu contenido. Puedes eliminar una sola página, varias páginas o rangos completos en una sola operación y luego descargar el archivo depurado." },
    { question: "¿Puedo eliminar varias páginas a la vez?", answer: "Sí. Puedes eliminar páginas individuales, varias páginas dispersas o rangos de páginas completos en una sola acción. Esto facilita quitar rápidamente páginas en blanco, secciones innecesarias o material confidencial antes de compartir el documento." },
    { question: "¿Eliminar páginas modificará mi archivo original?", answer: "No. El proceso no es destructivo, por lo que tu PDF original permanece intacto hasta que descargues la versión modificada. Siempre trabajas sobre una copia, lo que significa que puedes experimentar libremente sin arriesgar el documento original." },
    { question: "¿Quitar páginas afecta la calidad del resto?", answer: "En absoluto. Cada página que permanece conserva su formato, imágenes y calidad de texto originales. Eliminar páginas solo descarta las que seleccionas, dejando el contenido restante exactamente como aparecía en el PDF original." },
    { question: "¿Es privado eliminar páginas de documentos sensibles?", answer: "Sí. Todo el procesamiento ocurre localmente en tu navegador, por lo que los archivos que contienen información confidencial nunca se suben a ningún servidor. Esto hace que sea seguro quitar páginas privadas de contratos, informes o registros escaneados en tu propio dispositivo." },
  ],
  "extract-pages": [
    { question: "¿Cómo extraigo páginas específicas de un PDF?", answer: "Elige las páginas que quieras y la herramienta crea un nuevo PDF que contiene solo esas páginas. Puedes extraer una sola página, varias páginas o rangos completos y luego descargar un documento enfocado que incluye únicamente el contenido que seleccionaste." },
    { question: "¿Las páginas extraídas conservan el texto buscable y seleccionable?", answer: "Sí. La herramienta conserva las fuentes, el diseño, las imágenes y el texto originales, por lo que las páginas extraídas se ven idénticas al origen. El texto sigue siendo totalmente buscable y seleccionable, lo cual es útil al extraer capítulos o secciones de informes que reutilizarás más adelante." },
    { question: "¿Cuál es la diferencia entre extraer y dividir páginas?", answer: "Extraer reúne solo las páginas que eliges en un nuevo documento, ideal para crear un archivo enfocado a partir de páginas dispersas. Dividir separa un PDF en varios archivos independientes. Usa extraer cuando quieras una única colección personalizada de páginas específicas." },
    { question: "¿Puedo extraer páginas no consecutivas en un solo documento?", answer: "Sí. Puedes seleccionar páginas individuales de diferentes partes del PDF, así como rangos continuos, y se combinan en un único archivo nuevo. Esto es excelente para armar un documento personalizado solo con las secciones relevantes." },
    { question: "¿Están seguros mis archivos al extraer páginas?", answer: "Por supuesto. La extracción se ejecuta enteramente en tu navegador, por lo que tus documentos nunca salen de tu dispositivo ni se suben a ningún lugar. Puedes extraer páginas de informes confidenciales o libros de texto con la tranquilidad de que nada se envía a un servidor." },
  ],
  "reorder": [
    { question: "¿Cómo reorganizo las páginas de un PDF?", answer: "Abre tu PDF para ver vistas previas en miniatura de cada página y luego arrastra cualquier página a una nueva posición. El diseño visual facilita ubicar y mover las páginas correctas, y puedes ver una vista previa del nuevo orden antes de descargar." },
    { question: "¿Puedo mover varias páginas juntas al reordenar?", answer: "Sí. Puedes arrastrar las páginas una a una o seleccionar varias páginas y moverlas como un grupo. Esto agiliza las reorganizaciones más grandes, como desplazar una sección completa de un informe a otro lugar del documento." },
    { question: "¿La herramienta muestra miniaturas de las páginas mientras reordeno?", answer: "Sí. Cada página aparece como una vista previa en miniatura, para que veas con claridad lo que estás moviendo y confirmes la disposición visualmente. Esto hace que corregir un escaneo desordenado o reestructurar el contenido sea mucho más fácil que trabajar solo con números de página." },
    { question: "¿Reordenar las páginas reducirá la calidad del documento?", answer: "No. Reorganizar las páginas conserva todo el formato, las imágenes y la calidad de texto del original. La herramienta solo cambia la secuencia de páginas, por lo que cada página mantiene su nitidez completa y sigue siendo buscable en el documento reordenado." },
    { question: "¿El reordenamiento se realiza de forma privada en mi navegador?", answer: "Sí. Todo el proceso de arrastrar y soltar ocurre localmente en tu dispositivo, sin subir archivos a ningún servidor. Tus documentos permanecen privados, lo que hace seguro reorganizar PDF sensibles o confidenciales." },
  ],
  "rotate": [
    { question: "¿Cómo roto páginas en un PDF?", answer: "Elige las páginas que quieras girar y selecciona una rotación de 90, 180 o 270 grados. Puedes rotar todo a la vez o corregir solo las páginas con la orientación incorrecta y luego descargar el documento corregido de inmediato." },
    { question: "¿Puedo rotar solo una página en lugar de todo el PDF?", answer: "Sí. La herramienta te permite rotar páginas específicas individualmente, de modo que puedes corregir solo las capturadas en el ángulo incorrecto dejando el resto exactamente como estaba. Esto es ideal para corregir errores de escaneo aislados." },
    { question: "¿Qué ángulos de rotación están disponibles?", answer: "Puedes rotar las páginas 90, 180 o 270 grados. Estos cubren las correcciones de orientación habituales, ya sea que una página escaneada haya quedado de lado, al revés o necesite girarse para cumplir un requisito específico de visualización o impresión." },
    { question: "¿Rotar afecta la calidad del texto o las imágenes?", answer: "No. La rotación conserva toda la calidad del contenido, incluidos el texto, las imágenes y el formato. El texto rotado sigue siendo buscable y seleccionable, por lo que el documento mantiene toda su funcionalidad y se ve igual de nítido que antes, solo que en el ángulo corregido." },
    { question: "¿Se suben mis archivos cuando roto páginas?", answer: "No. La rotación ocurre al instante dentro de tu navegador, por lo que tus documentos nunca salen de tu dispositivo. Este procesamiento local mantiene los registros escaneados o los archivos privados completamente confidenciales mientras corriges su orientación." },
  ],
  "insert-blank": [
    { question: "¿Cómo inserto páginas en blanco en un PDF?", answer: "Especifica dónde quieres que vayan las páginas vacías y cuántas agregar. La herramienta inserta páginas en blanco al principio, al final o entre cualquier página existente, y luego te permite descargar el documento actualizado de inmediato." },
    { question: "¿Dónde puedo agregar páginas en blanco en mi documento?", answer: "Puedes insertarlas al principio, al final o entre dos páginas existentes cualesquiera. Solo elige la posición exacta y el número de páginas a agregar, lo que te da control total sobre dónde aparece el nuevo espacio." },
    { question: "¿Qué tamaño tendrán las páginas en blanco insertadas?", answer: "Las páginas en blanco coinciden automáticamente con el tamaño y la orientación de las páginas existentes de tu documento. Esto mantiene el archivo coherente para imprimir o encuadernar, de modo que el espacio agregado se integra sin problemas con el resto de tu PDF." },
    { question: "¿Por qué agregaría páginas en blanco a un PDF?", answer: "Las razones comunes incluyen dejar espacio para notas escritas a mano, crear saltos de página para imprimir, preparar un documento para encuadernar o reservar espacios de marcador de posición para contenido que agregarás más adelante. La herramienta hace que cualquiera de estas tareas sea rápida de configurar." },
    { question: "¿Insertar páginas en blanco es gratuito y privado?", answer: "Sí en ambos casos. La herramienta es gratuita y sin registro, y todo el procesamiento se ejecuta localmente en tu navegador. Tu archivo nunca se sube a un servidor, por lo que el documento permanece privado de principio a fin." },
  ],
  "duplicate-pages": [
    { question: "¿Cómo duplico páginas dentro de un PDF?", answer: "Selecciona las páginas que quieras copiar y elige dónde deben ir los duplicados. La herramienta crea copias exactas y las coloca en la posición que especifiques, y luego te permite descargar el documento actualizado de inmediato." },
    { question: "¿Puedo duplicar más de una página a la vez?", answer: "Sí. Puedes copiar una sola página o varias páginas en una sola operación y colocar los duplicados en cualquier lugar del documento. Esto resulta útil para repetir un formulario rellenable o una página de plantilla varias veces sin copiar y pegar manualmente." },
    { question: "¿Los duplicados son copias exactas de los originales?", answer: "Lo son. Cada duplicado conserva todo el formato, las imágenes, el texto y los elementos visuales de la página de origen, por lo que la copia es idéntica en apariencia y funcionalidad. No se pierde ni se altera nada durante la duplicación." },
    { question: "¿Dónde puedo colocar las páginas duplicadas?", answer: "Puedes ubicar las copias en cualquier punto de tu documento, no solo junto a las originales. Esto te permite crear un PDF con formularios, plantillas o páginas de respaldo repetidos dispuestos exactamente donde los necesites." },
    { question: "¿Duplicar páginas mantiene mis archivos privados?", answer: "Sí. Toda la duplicación se ejecuta en tu navegador, por lo que tus documentos nunca salen de tu dispositivo ni llegan a un servidor. Puedes copiar páginas de formularios o plantillas sensibles con total privacidad y seguridad." },
  ],
  "reverse-order": [
    { question: "¿Cómo invierto el orden de las páginas en mi PDF?", answer: "Sube tu PDF y la herramienta invierte al instante toda la secuencia de páginas, de modo que la última página pasa a ser la primera y la primera pasa a ser la última. No hay nada que configurar. Una vez invertido, puedes descargar el nuevo PDF de inmediato." },
    { question: "¿Invertir el orden cambiará el contenido o la calidad de mis páginas?", answer: "No. Solo cambia la secuencia de las páginas. Cada página conserva su texto, imágenes, formato y resolución originales exactamente como estaban. Las páginas en sí permanecen intactas, solo se reorganizan de la última a la primera, así que la calidad sigue siendo idéntica a la de tu archivo de origen." },
    { question: "¿Puedo arreglar un PDF que se escaneó al revés con esta herramienta?", answer: "Sí, es un uso habitual. Si tu escáner capturó las páginas en orden inverso, esta herramienta invierte toda la secuencia para devolverla al orden correcto de principio a fin con un solo clic, ahorrándote tener que reordenar cada página manualmente." },
    { question: "¿La herramienta para invertir el orden de las páginas es gratuita?", answer: "Completamente gratuita y sin necesidad de registro. Puedes invertir tantos PDF como quieras sin coste alguno. No se añaden marcas de agua ni hay que crear cuentas antes de descargar tu documento invertido." },
    { question: "¿Mis archivos se mantienen privados al invertir el orden de las páginas?", answer: "Sí. Todo el procesamiento ocurre localmente en tu navegador, por lo que tu PDF nunca se sube a ningún servidor. Tu documento permanece por completo en tu dispositivo durante toda la inversión, manteniendo los archivos confidenciales totalmente privados." },
  ],
  "split-by-size": [
    { question: "¿Cómo funciona dividir un PDF por tamaño de archivo?", answer: "Estableces un límite máximo de tamaño y la herramienta analiza tu PDF y lo divide en puntos adecuados para que cada archivo resultante se mantenga por debajo de ese límite. Sube tu documento, elige el tamaño objetivo y descarga los archivos más pequeños resultantes." },
    { question: "¿Qué unidades de tamaño puedo establecer como límite?", answer: "Puedes especificar tu máximo en KB, MB o GB, lo que te da un control preciso sobre los tamaños de salida. Esto facilita ajustarse a los límites de los archivos adjuntos de correo electrónico, las restricciones de almacenamiento en la nube o cualquier requisito específico de tamaño de archivo de una plataforma para tus archivos divididos." },
    { question: "¿Puedo descargar todos los archivos divididos a la vez?", answer: "Sí. Después de dividir, puedes obtener cada archivo resultante de forma individual o descargarlos todos juntos como un único archivo ZIP, lo cual resulta cómodo cuando tu PDF se divide en varias partes." },
    { question: "¿Cada archivo dividido conservará la misma calidad que el original?", answer: "Cada archivo resultante conserva todo el formato, las imágenes y la calidad del texto de tu documento de origen. La herramienta solo divide el contenido en archivos más pequeños para cumplir con tu límite de tamaño; no comprime ni degrada las páginas de ninguna forma." },
    { question: "¿Es seguro dividir documentos confidenciales por tamaño?", answer: "Sí. Toda la división ocurre en tu navegador, en tu propio dispositivo, por lo que tu PDF nunca se sube a ningún sitio. Incluso los documentos grandes o sensibles se mantienen privados, lo cual da tranquilidad al preparar archivos para enviar por correo electrónico o compartir." },
  ],
  "split-by-bookmarks": [
    { question: "¿Cómo decide la función Dividir por marcadores dónde dividir mi PDF?", answer: "La herramienta lee la estructura de marcadores o capítulos existente de tu PDF y divide en esos puntos, convirtiendo cada sección de marcador en su propio archivo independiente. Tú eliges en qué nivel de marcador dividir, de modo que las divisiones coincidan con el esquema de tu documento." },
    { question: "¿Puedo elegir en qué nivel de marcador dividir?", answer: "Sí. La herramienta detecta todos los marcadores y te permite seleccionar el nivel, ya sean capítulos de nivel superior, subsecciones o niveles más anidados. Esta flexibilidad te permite dividir un documento en unos pocos capítulos grandes o en muchas partes más pequeñas." },
    { question: "¿Qué pasa si mi PDF no tiene marcadores?", answer: "Esta herramienta depende de una estructura de marcadores existente para determinar los puntos de división, por lo que funciona mejor con PDF que ya tienen capítulos o un esquema, como manuales, libros de texto o documentos legales. Sin marcadores, no hay puntos de referencia por los que dividir." },
    { question: "¿Se conservan los marcadores en los archivos resultantes?", answer: "Sí. Cada archivo dividido conserva los marcadores que contiene, junto con todo el formato, las imágenes y la calidad del texto del original. Los capítulos siguen siendo navegables, así que tu estructura organizada se traslada a los documentos más pequeños." },
    { question: "¿Mis archivos se mantienen privados al dividir por marcadores?", answer: "Por supuesto. Todo el procesamiento se ejecuta localmente en tu navegador, por lo que tu PDF nunca se envía a un servidor. Tus documentos estructurados permanecen en tu dispositivo, y puedes descargar los archivos divididos de forma individual o como un único archivo ZIP." },
  ],
  "sign": [
    { question: "¿Cómo puedo añadir mi firma a un PDF?", answer: "Tienes tres opciones: dibujar tu firma con el ratón o el panel táctil, escribir tu nombre con una selección de fuentes o subir una imagen de tu firma existente. Luego colócala en cualquier lugar de cualquier página y descarga el PDF firmado." },
    { question: "¿Puedo posicionar y cambiar el tamaño de mi firma en la página?", answer: "Sí. La herramienta ofrece una colocación flexible, que te permite arrastrar tu firma a cualquier punto de cualquier página y cambiar su tamaño para que encaje. Esto resulta útil para líneas de firma, iniciales o para ajustar tu marca de forma ordenada dentro de un campo de formulario." },
    { question: "¿La firma se incrusta realmente en el documento?", answer: "Sí. Tu firma se incrusta directamente en el PDF, pasando a formar parte del propio documento en lugar de ser una capa superpuesta independiente. El archivo firmado mantiene una alta calidad y está listo para descargar y compartir inmediatamente después de firmar." },
    { question: "¿Firmar PDF aquí es gratuito y privado?", answer: "Es gratuito, sin registro y totalmente privado. Todo el procesamiento ocurre localmente en tu navegador, por lo que los datos de tu firma y el documento nunca salen de tu dispositivo. Eso lo hace muy adecuado para firmar contratos o formularios de forma remota sin necesidad de imprimir." },
    { question: "¿Puedo firmar un PDF en mi teléfono o tableta?", answer: "Sí. Como se ejecuta en el navegador, puedes dibujar tu firma directamente con una pantalla táctil en el móvil o la tableta, o bien escribirla o subirla. Funciona sin instalar ninguna aplicación ni imprimir el documento." },
  ],
  "redact": [
    { question: "¿La censura con esta herramienta es permanente?", answer: "Sí. La herramienta tacha por completo la información seleccionada y la elimina para que no se pueda recuperar ni extraer del documento posteriormente. Esta eliminación irreversible es lo que la hace segura para compartir archivos sensibles." },
    { question: "¿Qué puedo censurar en mi PDF?", answer: "Puedes seleccionar áreas o texto específicos para tacharlos, lo que te da un control preciso sobre lo que se elimina. Censura palabras individuales, imágenes o secciones enteras, algo idóneo para documentos legales, historiales médicos, estados financieros y todo lo que contenga información personal." },
    { question: "¿En qué se diferencia esto de simplemente dibujar un recuadro negro sobre el texto?", answer: "A diferencia de una simple capa superpuesta, esta herramienta elimina permanentemente la información subyacente en lugar de solo ocultarla visualmente. Con un recuadro dibujado, el texto oculto todavía se puede copiar; aquí el contenido sensible desaparece de verdad y es irrecuperable." },
    { question: "¿La censura reduce la calidad del resto del documento?", answer: "No. Solo se eliminan las áreas censuradas. Todo el contenido visible conserva su alta calidad, formato y resolución originales. Puedes descargar el PDF censurado de inmediato, listo para compartir con las partes sensibles borradas de forma permanente." },
    { question: "¿Mis archivos están seguros durante la censura?", answer: "Sí. Cada paso ocurre localmente en tu navegador, por lo que tu documento nunca se sube a ningún servidor. Los archivos legales, médicos o financieros sensibles permanecen por completo en tu dispositivo durante todo el proceso de censura, garantizando una privacidad total." },
  ],
  "remove-hidden-data": [
    { question: "¿Qué elimina exactamente Sanitizar PDF de mi archivo?", answer: "Elimina la información del autor, las fechas de creación y modificación, los detalles del software, los comentarios, las anotaciones, los datos de los campos de formulario, el JavaScript, los archivos incrustados y otro contenido oculto. Todo lo que puedes ver en la página se mantiene, mientras que los metadatos y los scripts invisibles se limpian." },
    { question: "¿Sanitizar cambiará el aspecto de mi documento?", answer: "No. El proceso conserva todo el contenido visible, el texto, las imágenes y el formato exactamente como aparecen. Solo se eliminan los datos ocultos y potencialmente sensibles, así que el PDF limpio se ve idéntico sin llevar consigo nada de los metadatos subyacentes." },
    { question: "¿Por qué debería sanitizar un PDF antes de compartirlo?", answer: "Los metadatos ocultos pueden filtrar tu nombre, el software que usaste, el historial de ediciones o scripts incrustados a cualquiera que abra el archivo. Sanitizar evita esa fuga de información, algo que importa al publicar documentos o al enviarlos a terceros." },
    { question: "¿También elimina el JavaScript y los archivos incrustados?", answer: "Sí. Más allá de los metadatos, la herramienta elimina el JavaScript incrustado, los archivos adjuntos y otro contenido potencialmente inseguro, lo que hace que el PDF resultante sea más limpio y seguro de distribuir, no solo despojado de los datos de autoría." },
    { question: "¿El proceso de sanitización es privado?", answer: "Completamente. Toda la limpieza ocurre localmente en tu navegador, por lo que tu documento nunca sale de tu dispositivo. Eso es especialmente apropiado para una herramienta de privacidad, ya que tu archivo no se sube a ningún sitio mientras se eliminan sus datos ocultos." },
  ],
  "certificate": [
    { question: "¿Qué formatos de certificado admite la firma con certificado?", answer: "Funciona con certificados digitales X.509 estándar en formatos .pfx y .p12. También puedes añadir detalles como el motivo de la firma y tu ubicación, que se incrustan junto con la firma criptográfica en el documento." },
    { question: "¿En qué se diferencia la firma con certificado de una firma normal?", answer: "Una firma visual solo muestra un gráfico, mientras que un certificado proporciona una prueba criptográfica de identidad e integridad del documento. Crea un sello a prueba de manipulaciones que revela si el archivo se alteró después de firmarlo, lo que lo hace legalmente vinculante en muchas jurisdicciones." },
    { question: "¿La firma mostrará si alguien modifica el documento más adelante?", answer: "Sí. La firma con certificado incrusta un sello a prueba de manipulaciones en el PDF. Si el documento se modifica después de firmarlo, la firma queda invalidada, alertando a los destinatarios de que la integridad del archivo se vio comprometida después de que lo firmaras." },
    { question: "¿Mi certificado y mi clave privada están seguros con esta herramienta?", answer: "Sí. Toda la firma ocurre localmente en tu navegador, por lo que tu certificado y tus claves privadas nunca salen de tu dispositivo ni se suben a ningún servidor. Esto mantiene protegidas tus credenciales sensibles mientras aplicas una firma verificada." },
    { question: "¿Quién debería usar la firma basada en certificado?", answer: "Es idónea para cualquiera que necesite firmas verificadas y legalmente sólidas, como profesionales del derecho que firman contratos, empleados públicos que gestionan documentos oficiales o empresas que aprueban formularios donde se requiere una prueba criptográfica de identidad e integridad del documento." },
  ],
  "pdf-to-images": [
    { question: "¿A qué formatos de imagen puedo exportar las páginas del PDF?", answer: "Puedes elegir PNG, JPEG o WebP. PNG mantiene una calidad perfecta y admite transparencia, JPEG produce archivos más pequeños con buena calidad, y WebP ofrece una compresión moderna con una excelente relación calidad-tamaño para la web." },
    { question: "¿Puedo convertir solo algunas páginas en lugar de todo el PDF?", answer: "Sí. Puedes seleccionar páginas específicas para convertir o procesar todo el documento de una vez. Cada página se convierte en su propio archivo de imagen independiente, lo que resulta útil para extraer un solo gráfico o generar miniaturas." },
    { question: "¿Las imágenes convertidas conservarán la calidad original?", answer: "Cada página se renderiza a su resolución original, conservando el texto, las imágenes, los gráficos y el diseño. Elegir PNG ofrece una calidad sin pérdidas con transparencia, de modo que las imágenes exportadas reproducen fielmente cómo se ve cada página en el PDF de origen." },
    { question: "¿Cómo descargo varias imágenes convertidas?", answer: "Después de la conversión, puedes guardar cada imagen de forma individual o descargarlas todas juntas como un único archivo ZIP. La opción ZIP resulta cómoda cuando has convertido muchas páginas y quieres tenerlas empaquetadas en un solo archivo." },
    { question: "¿Mis PDF se mantienen privados durante la conversión a imágenes?", answer: "Sí. Toda la conversión se ejecuta localmente en tu navegador, por lo que tu PDF nunca se sube a un servidor. Tu documento permanece en tu dispositivo mientras cada página se convierte en una imagen PNG, JPEG o WebP." },
  ],
  "images-to-pdf": [
    { question: "¿Qué formatos de imagen puedo combinar en un PDF?", answer: "Puedes arrastrar archivos PNG, JPEG, WebP, GIF y BMP, y mezclar formatos libremente en un mismo documento. Las imágenes WebP se procesan automáticamente en segundo plano, y cada imagen que añadas se convierte en su propia página dentro del PDF terminado." },
    { question: "¿Cómo establezco el orden de las imágenes en mi PDF?", answer: "Después de subirlas, solo tienes que arrastrar y soltar las miniaturas para colocarlas en el orden que prefieras antes de generar el archivo. Las páginas aparecen exactamente en ese orden, lo que facilita crear álbumes de fotos o ensamblar documentos escaneados correctamente." },
    { question: "¿Puedo elegir el tamaño y la orientación de la página?", answer: "Sí. Elige A4, Letter, A3, A5 o un tamaño personalizado, selecciona orientación vertical u horizontal, añade márgenes y decide si cada imagen se ajusta dentro de la página o si la página se adapta a la imagen. Estas opciones te permiten personalizar el diseño según tus necesidades." },
    { question: "¿Se suben mis imágenes a un servidor?", answer: "No. Todo funciona localmente en tu navegador utilizando el propio procesamiento de tu dispositivo, así que tus fotos y escaneos nunca salen de tu computadora. No hay subidas ni cuentas, lo que mantiene tus imágenes personales o sensibles completamente privadas." },
    { question: "¿La conversión reduce la calidad de mi imagen?", answer: "Tus imágenes conservan su resolución y color originales al colocarse en el PDF. Si activas el ajuste a la página, las imágenes grandes se reducen para encajar de forma ordenada en la página, pero nunca se amplían, por lo que la nitidez y el detalle se mantienen intactos en el documento final." },
  ],
  "pdf-to-word": [
    { question: "¿El conversor mantiene mi formato en Word?", answer: "Reconstruye el documento detectando líneas y párrafos, y traslada los tamaños de fuente y el texto en negrita donde puede. Se añaden saltos de página entre las páginas para que el DOCX editable se mantenga cercano en estructura al diseño original del PDF." },
    { question: "¿Funcionará con un PDF escaneado?", answer: "Los PDF escaneados o de solo imagen no tienen texto seleccionable que extraer, por lo que la herramienta no puede sacar palabras de ellos, ya que no ejecuta OCR. Funciona mejor con PDF que ya contienen texto real, legible por máquina, en lugar de imágenes de texto." },
    { question: "¿Puedo convertir solo ciertas páginas?", answer: "Sí. Introduce un rango de páginas como 1-5, o una combinación como 1,3,7-9, y solo esas páginas se convierten en el archivo de Word. Déjalo en blanco o escribe \"all\" para convertir todo el documento de una vez." },
    { question: "¿La conversión de PDF a Word es gratuita y privada?", answer: "Es completamente gratuita y sin registro, y la conversión ocurre por completo dentro de tu navegador. Tu PDF nunca se envía a un servidor, lo que significa que los contratos, informes o documentos personales confidenciales permanecen en tu propio dispositivo." },
    { question: "¿Qué archivo produce y puedo abrirlo en cualquier lugar?", answer: "Obtienes un archivo .docx estándar que se abre en Microsoft Word, Google Docs, LibreOffice y la mayoría de los demás procesadores de texto. Una vez descargado, puedes editar, reformatear y reutilizar el texto igual que en cualquier documento normal de Word." },
  ],
  "pdf-to-excel": [
    { question: "¿Cómo detecta las tablas en mi PDF?", answer: "La herramienta analiza la posición de cada elemento de texto, agrupando los elementos de una misma línea en filas y alineando las posiciones horizontales compartidas en columnas. Cuando encuentra una cuadrícula clara, construye una hoja de cálculo adecuada; de lo contrario, recurre a filas línea por línea." },
    { question: "¿Las páginas múltiples se colocan en una sola hoja o en varias?", answer: "Cada página del PDF se convierte en su propia pestaña de hoja de cálculo dentro del libro, etiquetada por número de página, y las columnas se ajustan automáticamente para mayor legibilidad. Esto mantiene los datos de diferentes páginas separados y fáciles de navegar dentro de Excel." },
    { question: "¿Puede extraer tablas de una factura o informe escaneado?", answer: "Solo si el PDF contiene texto real. Los documentos escaneados son imágenes, y esta herramienta no realiza OCR, por lo que no puede leer cifras de una foto de una página. Usa PDF con texto seleccionable real para una extracción precisa." },
    { question: "¿Qué formato obtengo y la herramienta es gratuita?", answer: "Recibes un archivo .xlsx listo para usar que se abre en Excel, Google Sheets o LibreOffice Calc, y la herramienta es totalmente gratuita sin necesidad de cuenta. A partir de ahí puedes editar, ordenar y ejecutar fórmulas sobre los datos." },
    { question: "¿Están seguros mis datos financieros durante la conversión?", answer: "Totalmente. Toda la extracción de tablas se ejecuta localmente en tu navegador, por lo que las facturas, los estados de cuenta y los informes financieros nunca se suben a ningún lugar. Tus cifras sensibles permanecen en tu máquina desde el inicio hasta la hoja de cálculo terminada." },
  ],
  "pdf-to-text": [
    { question: "¿El texto extraído mantiene el orden de lectura original?", answer: "Sí. La herramienta ordena el texto por posición vertical y horizontal, de modo que las líneas salen de arriba hacia abajo y de izquierda a derecha, tal como leerías la página. El resultado es un archivo .txt limpio, sin códigos de formato ni caracteres extraños." },
    { question: "¿Puedo extraer texto de solo unas pocas páginas?", answer: "Puedes especificar un rango de páginas como 2-6 o una lista como 1,4,9 para extraer texto únicamente de esas páginas. También hay una opción para etiquetar cada página con su número en el resultado si deseas marcadores de página claros." },
    { question: "¿Extraerá texto de un documento escaneado?", answer: "Los PDF escaneados son imágenes de texto, y este extractor lee el texto incrustado en lugar de ejecutar OCR, por lo que no puede reconocer palabras dentro de una imagen. Destaca con los PDF digitales que ya contienen contenido de texto real y seleccionable." },
    { question: "¿La herramienta es gratuita y sube mi PDF?", answer: "Es gratuita y sin registro, y no se sube nada. La extracción ocurre directamente en tu navegador, en tu propio dispositivo, así que incluso las investigaciones confidenciales o los documentos privados nunca viajan a ningún servidor." },
    { question: "¿Qué puedo hacer con el texto sin formato después?", answer: "El resultado .txt limpio es ideal para el análisis de texto, la indexación para búsquedas, copiar contenido en otras aplicaciones o introducirlo en scripts y otras herramientas de procesamiento. Al ser texto plano UTF-8, funciona con prácticamente cualquier editor o programa." },
  ],
  "pdf-to-csv": [
    { question: "¿Puedo cambiar el delimitador o el carácter de comillas en el CSV?", answer: "Sí. Puedes establecer un delimitador personalizado, como un punto y coma en lugar de una coma, y elegir el carácter de comillas usado para envolver los valores. Los campos que contienen delimitadores, comillas o saltos de línea se escapan automáticamente para que el CSV se importe sin problemas." },
    { question: "¿Crea un solo CSV o un archivo separado por página?", answer: "Tú decides. De forma predeterminada, todas las páginas se combinan en un único CSV con marcadores de página, o puedes activar archivos separados por página. Cuando hay varios archivos, se agrupan en un ZIP para una sola descarga." },
    { question: "¿Qué tan bien maneja las tablas de varias columnas?", answer: "La herramienta mapea la posición de cada elemento de texto para detectar filas y columnas, y luego alinea las celdas en una cuadrícula estructurada. Funciona mejor con tablas claramente dispuestas; las páginas con formato poco definido pueden recurrir a un resultado más simple, fila por fila." },
    { question: "¿Funcionará con una tabla de un PDF escaneado?", answer: "No, porque las páginas escaneadas son imágenes y la herramienta lee el texto incrustado sin OCR. Para obtener un resultado CSV fiable, usa PDF que contengan texto seleccionable genuino en lugar de tablas fotografiadas o escaneadas." },
    { question: "¿Es gratuita y se mantienen privados mis datos?", answer: "El conversor es gratuito y sin cuenta, y todo el procesamiento permanece dentro de tu navegador, en tu dispositivo. Tus datos tabulares nunca se suben, así que las tablas financieras o de investigación se mantienen confidenciales mientras las conviertes en CSV." },
  ],
  "pdf-to-html": [
    { question: "¿Puedo incluir imágenes en el resultado HTML?", answer: "Hay una opción para incrustar las imágenes directamente como datos base64, de modo que el HTML sea autónomo y no dependa de archivos de imagen separados. Puedes omitir las imágenes para obtener una página más ligera y centrada en el texto cuando eso se ajuste mejor a tus necesidades." },
    { question: "¿Puedo aplicar mi propio CSS a la página convertida?", answer: "Sí. Puedes proporcionar estilos CSS personalizados para controlar el aspecto del HTML generado, lo que te permite ajustarlo al diseño o formato de tu sitio. El resultado se abre en cualquier navegador y puede refinarse aún más en cualquier editor HTML." },
    { question: "¿Qué páginas se convierten a HTML?", answer: "De forma predeterminada se convierte todo el documento, pero puedes introducir un rango de páginas como 1-4 o una lista como 2,5,8 para convertir a HTML solo las páginas seleccionadas. Esto es útil cuando solo necesitas parte de un PDF largo en la web." },
    { question: "¿La conversión es gratuita y permanece en mi dispositivo?", answer: "Es gratuita y sin registro, y toda la conversión se ejecuta localmente en tu navegador. Tu PDF nunca se envía a ningún lugar, así que incluso los documentos no publicados o sensibles permanecen privados mientras los preparas para la web." },
    { question: "¿Qué puedo hacer con el archivo HTML después?", answer: "El resultado es un archivo HTML listo para la web que puedes publicar en línea, incrustar en un sitio o abrir en cualquier navegador. Los caracteres especiales se escapan correctamente, así que el marcado queda limpio y listo para seguir editándolo en tus herramientas." },
  ],
  "pdf-to-markdown": [
    { question: "¿Detecta automáticamente los encabezados?", answer: "Sí. El conversor analiza el texto y puede marcar los encabezados probables con la sintaxis de encabezados de Markdown, ayudando a preservar la jerarquía del documento. Esto hace que el resultado esté listo para incorporarlo a documentación o a un blog con la estructura intacta." },
    { question: "¿Cómo se manejan los caracteres especiales en el Markdown?", answer: "Los caracteres que tienen significado en Markdown, como asteriscos, guiones bajos, corchetes y comillas invertidas, se escapan para que se muestren como texto plano en lugar de romper el formato. Eso mantiene tu contenido convertido renderizándose correctamente dondequiera que lo pegues." },
    { question: "¿Puedo convertir solo páginas específicas a Markdown?", answer: "Puedes introducir un rango de páginas como 1-3 o una lista como 2,4,6 para convertir solo esas páginas. Dejar el campo vacío o introducir \"all\" procesa el documento completo en un único archivo Markdown." },
    { question: "¿Es gratuito y se sube mi PDF a algún lugar?", answer: "La herramienta es gratuita sin necesidad de cuenta, y la conversión ocurre por completo en tu navegador. No se sube nada a un servidor, así que los documentos técnicos o borradores que aún no estés listo para compartir permanecen completamente en tu propio dispositivo." },
    { question: "¿Por qué usar Markdown en lugar de otro formato?", answer: "Markdown es texto plano, por lo que el resultado es ligero, fácil de editar en cualquier editor y funciona sin problemas con sistemas de control de versiones como Git. Eso lo hace ideal para documentación, redacción técnica y publicaciones de blog." },
  ],
  "compress": [
    { question: "¿Cuánto puede reducir mi PDF?", answer: "El ahorro depende del contenido del archivo y del nivel de calidad que elijas. La herramienta reestructura el PDF usando flujos de objetos y puede eliminar metadatos, lo que reduce la sobrecarga. Los documentos con muchas imágenes y sobrecargados suelen ser los que más se benefician." },
    { question: "¿Comprimir difuminará mi texto o mis imágenes?", answer: "El texto se mantiene nítido y permite búsquedas porque no se rasteriza. Eliges un nivel de calidad de bajo a alto para equilibrar el tamaño del archivo frente a la fidelidad, así que puedes favorecer archivos más pequeños o conservar más detalle según el documento." },
    { question: "¿Puedo eliminar los metadatos para hacer el archivo más pequeño y limpio?", answer: "Sí. Hay una opción para eliminar metadatos como el título, el autor y las palabras clave, lo que reduce ligeramente el tamaño y elimina detalles personales ocultos. Es útil antes de compartir un documento que prefieres que no quede etiquetado con tu información." },
    { question: "¿Hay un límite de tamaño de archivo?", answer: "No hay un límite fijo del lado del servidor porque la compresión se ejecuta localmente en tu navegador. El límite práctico depende de la memoria disponible de tu dispositivo, por lo que los archivos muy grandes funcionan, pero pueden tardar más en máquinas menos potentes." },
    { question: "¿Mis documentos son privados cuando los comprimo?", answer: "Totalmente. No se sube ningún archivo a ningún servidor; toda la optimización ocurre en tu propio dispositivo. Eso lo hace seguro para comprimir informes o contratos confidenciales que necesitas enviar por correo o archivar sin exponerlos en línea." },
  ],
  "add-watermark": [
    { question: "¿Cómo añado una marca de agua a mi PDF?", answer: "Sube tu PDF y luego elige una marca de agua de texto o de imagen y ajusta su posición, opacidad, rotación, tamaño y color. Puedes estamparla en todas las páginas o seleccionar páginas concretas. Cuando la vista previa se vea bien, descarga el archivo con la marca de agua directamente desde tu navegador." },
    { question: "¿Puedo usar el logotipo de mi empresa como marca de agua de imagen?", answer: "Sí. Además de marcas de agua de texto como Confidencial o Borrador, puedes subir una imagen, como el logotipo de tu empresa, y superponerla en las páginas. Ajusta su tamaño, opacidad y rotación para que la marca quede discreta en segundo plano o aparezca destacada y prominente." },
    { question: "¿Puedo poner la marca de agua solo en ciertas páginas en lugar de en todo el documento?", answer: "Por supuesto. No estás limitado a estamparla en todo. Selecciona páginas concretas para aplicar la marca de agua mientras dejas otras intactas, o aplícala de forma uniforme en todo el documento para mantener una imagen de marca coherente en informes, propuestas y otros archivos de varias páginas." },
    { question: "¿Añadir una marca de agua reducirá la calidad de mi PDF?", answer: "No. La marca de agua se superpone sobre tus páginas mientras el texto, las imágenes y el formato originales permanecen intactos debajo. El PDF resultante conserva su alta calidad, y puedes controlar la opacidad para que la marca proteja tu trabajo sin ocultar el contenido." },
    { question: "¿La herramienta de marca de agua es gratuita y mis documentos se mantienen privados?", answer: "Es completamente gratuita y no requiere registro. Cada paso se ejecuta localmente en tu navegador, por lo que tu PDF nunca se sube a ningún servidor. Los contratos sensibles, las propuestas y los archivos confidenciales permanecen por completo en tu dispositivo durante todo el proceso." },
  ],
  "page-numbers": [
    { question: "¿Cómo añado números de página a un PDF?", answer: "Abre tu PDF, elige dónde deben ir los números y luego descarga el resultado. Puedes colocarlos arriba o abajo y a la izquierda, en el centro o a la derecha, con control sobre la fuente, el tamaño y el número inicial para que coincidan con el estilo de tu documento." },
    { question: "¿Puedo elegir dónde aparecen los números de página y desde qué número empezar?", answer: "Sí. Tú decides la posición, ya sea arriba o abajo y alineada a la izquierda, en el centro o a la derecha, y puedes establecer un número inicial personalizado. Esto resulta útil cuando las páginas preliminares o una portada hacen que la página uno no deba ser la primera numerada." },
    { question: "¿Puedo omitir la numeración en la portada o en páginas concretas?", answer: "Puedes hacerlo. La herramienta te permite aplicar la numeración en todo el documento u omitir páginas seleccionadas, como portadas o páginas de título, de modo que solo las páginas que quieras lleven números, lo cual es ideal para informes y tesis." },
    { question: "¿Puedo personalizar la fuente y el tamaño de los números de página?", answer: "Por supuesto. Más allá de la posición, puedes ajustar la fuente y el tamaño de los números para que se integren con la tipografía de tu documento, manteniendo trabajos académicos, documentos legales y manuales impresos con un aspecto coherente y profesional." },
    { question: "¿Es gratis y mis archivos se mantienen privados?", answer: "Añadir números de página es gratis y no necesita cuenta. Todo el procesamiento ocurre localmente dentro de tu navegador, lo que significa que tu PDF nunca se envía a un servidor. Tus tesis, contratos e informes permanecen confidenciales en tu propia máquina." },
  ],
  "crop": [
    { question: "¿Cómo recorto páginas en un PDF?", answer: "Carga tu PDF y establece los límites de recorte de forma visual en la interfaz para eliminar márgenes o bordes. Aplica el mismo recorte a todas las páginas o ajústalas individualmente, y luego descarga el documento ya ordenado cuando se vea como quieres." },
    { question: "¿Puedo recortar cada página de forma diferente o solo todas las páginas igual?", answer: "Ambas opciones están disponibles. Puedes aplicar un único recorte uniforme en todo el documento para mayor rapidez, o ajustar páginas individuales cuando los escaneos tienen márgenes inconsistentes, lo que te da flexibilidad para material de origen mixto o irregular." },
    { question: "¿El recorte eliminará texto o imágenes dentro de mis páginas?", answer: "No. El recorte solo elimina el área que queda fuera de los límites que elijas. Todo el texto, las imágenes y el formato dentro de la región conservada se preservan exactamente, por lo que eliminas espacios en blanco o bordes negros del escáner sin perder contenido esencial." },
    { question: "¿Puedo usar la herramienta de recorte para eliminar bordes negros del escáner y márgenes?", answer: "Sí, ese es un uso principal. Es ideal para cortar los bordes negros que dejan los escáneres, eliminar el exceso de espacio en blanco alrededor de documentos escaneados y centrar las páginas en el contenido importante para una impresión más limpia y una lectura más cómoda en pantalla." },
    { question: "¿El recorte es gratis y mis archivos se suben a algún lugar?", answer: "La herramienta de recorte es gratuita y no requiere registro. No se sube nada; todo el proceso se ejecuta localmente en tu navegador, por lo que libros escaneados, documentos privados y cualquier PDF sensible nunca salen de tu dispositivo." },
  ],
  "resize": [
    { question: "¿Cómo cambio el tamaño de página de un PDF?", answer: "Sube tu PDF y elige un valor predeterminado como A4 o Letter, o introduce un ancho y un alto personalizados. La herramienta escala tu contenido a las nuevas dimensiones manteniendo la relación de aspecto, y luego te permite descargar el archivo redimensionado." },
    { question: "¿A qué tamaños y formatos de página puedo redimensionar?", answer: "Puedes seleccionar valores predeterminados comunes como A4 y Letter, o especificar tus propias dimensiones personalizadas. Esto facilita convertir entre estándares de papel regionales o ajustar las páginas a un requisito de diseño concreto para imprimir o compartir." },
    { question: "¿Redimensionar distorsionará o estirará mi contenido?", answer: "No. Al ajustar las páginas a nuevas dimensiones, la herramienta conserva la relación de aspecto para que el texto y las imágenes permanezcan proporcionados y legibles en lugar de estirados. El resultado mantiene su calidad, listo para imprentas o trabajos estandarizados." },
    { question: "¿Puedo estandarizar un documento con tamaños de página mixtos?", answer: "Sí. Si tienes páginas escaneadas de tamaños variados o un documento que mezcla formatos, puedes redimensionarlas todas a un tamaño uniforme, lo cual es ideal antes de enviar archivos a una imprenta o de unificar un PDF compilado." },
    { question: "¿La herramienta de redimensionar es gratuita y privada?", answer: "Es gratuita y sin registro. Todo el redimensionamiento se ejecuta localmente en tu navegador, por lo que tu PDF nunca se sube a ningún servidor. Tus documentos permanecen confidenciales en tu dispositivo de principio a fin." },
  ],
  "grayscale": [
    { question: "¿Cómo convierto un PDF a escala de grises?", answer: "Solo sube tu PDF a color y la herramienta convierte automáticamente cada página a blanco y negro. El texto, las imágenes y los gráficos en color se transforman en suaves tonos de gris, y puedes descargar el documento monocromático terminado de inmediato." },
    { question: "¿Convertir a escala de grises reduce el tamaño del archivo PDF?", answer: "A menudo lo hace. Eliminar la información de color de las imágenes y los gráficos puede reducir el archivo, lo cual resulta útil para enviar por correo, archivar o subir documentos. La conversión también crea un aspecto más uniforme manteniendo el detalle nítido." },
    { question: "¿Mi texto e imágenes seguirán nítidos tras la conversión a escala de grises?", answer: "Sí. La herramienta convierte los colores en suaves tonos de gris mientras preserva la nitidez y el detalle de tu texto, imágenes y gráficos, de modo que el resultado se mantiene limpio y legible en lugar de deslavado o borroso." },
    { question: "¿La escala de grises es buena para ahorrar en costes de impresión?", answer: "Por supuesto. Convertir a blanco y negro antes de imprimir te permite evitar el uso de tinta de color en documentos extensos, ahorrando dinero. Es una opción popular para imprimir informes y folletos de forma económica o archivar archivos en un formato monocromático coherente." },
    { question: "¿La herramienta de escala de grises es gratuita y mis archivos están seguros?", answer: "Convertir a escala de grises es gratis y no necesita cuenta. Todo ocurre localmente en tu navegador, por lo que no se sube ningún archivo a ningún servidor. Tus documentos permanecen completamente privados en tu propio dispositivo durante todo el proceso." },
  ],
  "invert-colors": [
    { question: "¿Cómo invierto los colores de un PDF para el modo oscuro?", answer: "Sube tu PDF y ejecuta la inversión en una sola operación. Los fondos blancos se vuelven oscuros y el texto negro se vuelve claro en todas las páginas, generando al instante una versión con tema oscuro que puedes descargar para una lectura cómoda en pantalla." },
    { question: "¿El texto seguirá siendo seleccionable tras invertir los colores?", answer: "Sí. La inversión cambia los colores manteniendo el texto nítido, legible y totalmente seleccionable, de modo que el documento sigue siendo funcional. Puedes buscar, resaltar y copiar texto igual que antes de la transformación." },
    { question: "¿Esto crea una experiencia de lectura en modo oscuro real?", answer: "Así es. Al volver oscuros los fondos blancos brillantes y mostrar texto claro sobre ellos, produce un PDF con tema oscuro y cómodo que reduce la fatiga visual durante la lectura nocturna o las largas sesiones frente a la pantalla en entornos con poca luz." },
    { question: "¿Puedo invertir los colores de todo el documento a la vez?", answer: "Sí. Una sola operación aplica la inversión a todas las páginas de todo el documento, por lo que no necesitas ajustar las páginas una a una. Obtienes un archivo con tema completamente oscuro listo para verse en pantalla en segundos." },
    { question: "¿Invertir los colores es gratis y mis archivos se mantienen privados?", answer: "La herramienta es gratuita y no requiere registro. Todo el procesamiento se ejecuta localmente en tu navegador, por lo que tu PDF nunca se sube a ningún lugar. Tus materiales de estudio y documentos permanecen confidenciales en tu dispositivo." },
  ],
  "flatten": [
    { question: "¿Cómo aplano un PDF?", answer: "Sube tu PDF y la herramienta combina los campos de formulario, las anotaciones y los elementos interactivos directamente en el contenido estático de la página. Los campos rellenables, las casillas de verificación, los comentarios y las marcas pasan a formar parte de la página, y puedes descargar el archivo bloqueado de inmediato." },
    { question: "¿Qué ocurre con mis campos de formulario rellenados cuando aplano?", answer: "Quedan bloqueados de forma permanente en la página. Tras aplanar, las casillas de verificación, los campos de texto y otras entradas pasan a formar parte del contenido estático, por lo que los destinatarios no pueden editar los datos. Esto es ideal para finalizar formularios completados antes de compartirlos o para archivar documentos firmados." },
    { question: "¿Por qué debería aplanar un PDF antes de compartirlo?", answer: "Aplanar impide que los destinatarios alteren los datos rellenados y garantiza que el documento se muestre de forma coherente en cualquier visor de PDF e impresora. Es perfecto para presentar formularios oficiales o distribuir archivos resistentes a manipulaciones y listos para imprimir que deben verse exactamente como se pretendía." },
    { question: "¿Aplanar también bloquea los comentarios y las anotaciones en la página?", answer: "Sí. Más allá de los campos de formulario, las anotaciones como comentarios y marcas también se combinan con el contenido de la página, de modo que el resultado visible se preserva exactamente sin que queden capas editables sobre el documento." },
    { question: "¿La herramienta de aplanar es gratuita y mis datos están seguros?", answer: "Aplanar es gratis y no necesita cuenta. Todo el procesamiento ocurre localmente en tu navegador, por lo que tus formularios completados y documentos firmados nunca se suben a un servidor. Tus datos sensibles permanecen privados en tu dispositivo." },
  ],
  "remove-annotations": [
    { question: "¿Cómo elimino las anotaciones de un PDF?", answer: "Sube tu PDF y la herramienta detecta y elimina cada capa de anotaciones en todas las páginas en una sola operación. Los comentarios, los resaltados, las notas adhesivas y las marcas se eliminan, dejando un documento limpio que puedes descargar de inmediato." },
    { question: "¿Qué tipos de marcas elimina esta herramienta?", answer: "Elimina comentarios, resaltados, notas adhesivas y otras marcas añadidas durante la revisión o la colaboración. Cada capa de anotaciones se detecta y se elimina de una vez, produciendo una versión pulida y libre de distracciones, sin desorden editorial." },
    { question: "¿Eliminar las anotaciones cambiará el texto o las imágenes originales?", answer: "No. Solo se eliminan las capas de anotaciones. El texto, las imágenes y el formato subyacentes se preservan exactamente como aparecen, por lo que obtienes una copia limpia sin alterar el contenido real del documento." },
    { question: "¿Puedo eliminar todas las notas de los revisores de una vez antes de publicar?", answer: "Sí. La herramienta elimina cada anotación en todas las páginas en una sola operación, lo que la hace perfecta para borrar los comentarios de los revisores de un borrador finalizado o para producir una copia profesional y limpia de un manuscrito con muchas marcas." },
    { question: "¿Eliminar anotaciones es gratis y mis archivos se mantienen privados?", answer: "La herramienta es gratuita y sin registro. Todo el procesamiento se ejecuta localmente en tu navegador, por lo que tu PDF nunca se sube a ningún servidor. Tus documentos revisados y borradores permanecen confidenciales en tu propio dispositivo." },
  ],
  "extract-images": [
    { question: "¿Cómo extraigo imágenes de un PDF con esta herramienta?", answer: "Sube tu PDF y la herramienta analiza cada página en busca de imágenes incrustadas y las extrae automáticamente. Puedes extraerlas de todas las páginas o especificar un rango de páginas y, luego, descargar los resultados. El proceso no implica selección manual ni capturas de pantalla." },
    { question: "¿En qué formatos de imagen puedo guardar las imágenes extraídas?", answer: "Puedes exportar las imágenes extraídas como archivos PNG o JPEG. El formato PNG conserva la calidad sin pérdidas, mientras que JPEG te permite establecer un nivel de calidad de compresión para obtener archivos más pequeños. Elige el formato que mejor se adapte a cómo planeas reutilizar las imágenes después." },
    { question: "¿Puedo descargar todas las imágenes extraídas a la vez?", answer: "Sí. Cuando un PDF contiene varias imágenes, la herramienta las agrupa en un único archivo ZIP para que puedas obtenerlas todas con un solo clic. Cada archivo se nombra según su página de origen, lo que mantiene tus gráficos extraídos organizados y fáciles de clasificar más adelante." },
    { question: "¿Las imágenes extraídas conservarán su calidad original?", answer: "La herramienta extrae las imágenes rasterizadas incrustadas cerca de su resolución almacenada, por lo que las fotos y los gráficos se mantienen nítidos. Elegir PNG las conserva sin pérdidas, mientras que la calidad de JPEG es ajustable. Ten en cuenta que las ilustraciones puramente vectoriales no son imágenes de píxeles y es posible que no se extraigan como archivos separados." },
    { question: "¿Mis archivos PDF se suben a algún sitio cuando extraigo imágenes?", answer: "No. Toda la extracción se ejecuta localmente dentro de tu navegador usando los propios recursos de tu dispositivo. Tu PDF nunca se envía a un servidor, por lo que los informes, contratos o documentos personales confidenciales permanecen completamente privados durante todo el proceso. La herramienta también es gratuita." },
  ],
  "remove-images": [
    { question: "¿Al eliminar las imágenes se borra el texto de mi PDF?", answer: "No. La herramienta elimina los objetos de imagen incrustados mientras deja intactos el texto, los gráficos vectoriales y el diseño de la página. El contenido escrito permanece totalmente legible y consultable, por lo que obtienes un documento limpio centrado en el texto en lugar de un archivo recortado o dañado." },
    { question: "¿Eliminar las imágenes hará que mi archivo PDF sea más pequeño?", answer: "Normalmente sí, y a menudo de forma drástica. Las imágenes suelen ser la parte más pesada de un PDF, por lo que eliminarlas puede reducir sustancialmente un informe voluminoso. Eso hace que el documento sea mucho más fácil de enviar por correo electrónico, subir a portales con límites de tamaño o almacenar sin ocupar espacio." },
    { question: "¿La herramienta elimina las imágenes de todas las páginas a la vez?", answer: "Sí. En una sola operación analiza todas las páginas y elimina los XObjects de imagen incrustados, las imágenes en línea y los operadores que las dibujan. No necesitas ir página por página; todo el documento se procesa de una sola pasada para obtener un resultado uniforme." },
    { question: "¿Esta herramienta es gratuita y necesito crear una cuenta?", answer: "Es completamente gratuita, sin registro, inicio de sesión ni marcas de agua. Solo abre la herramienta, suelta tu PDF y descarga la versión sin imágenes. No hay límites de uso ni muros de pago ocultos que bloqueen el resultado una vez finalizado el procesamiento." },
    { question: "¿Mis documentos están seguros cuando elimino las imágenes?", answer: "Todo ocurre localmente en tu navegador, por lo que tu PDF nunca se sube a ningún servidor. Los archivos confidenciales permanecen en tu propio dispositivo de principio a fin, lo que hace que la herramienta sea ideal para contratos sensibles, informes financieros y registros privados." },
  ],
  "optimize-images": [
    { question: "¿Cómo reduce esta herramienta el tamaño de mi archivo PDF?", answer: "Localiza las imágenes incrustadas dentro de tu PDF, reduce la escala de las que son más grandes de lo necesario y las vuelve a comprimir con ajustes eficientes. Dado que las imágenes suelen ser la parte más voluminosa de un documento, esto normalmente produce un archivo mucho más pequeño manteniendo las páginas con un aspecto nítido." },
    { question: "¿Puedo controlar la calidad y la resolución de la imagen?", answer: "Sí. Puedes establecer un nivel de calidad de compresión JPEG y una resolución máxima para el lado más largo de cada imagen. Los ajustes más bajos reducen el archivo de forma más agresiva, mientras que los más altos conservan más detalle, lo que te permite equilibrar el tamaño con la nitidez visual." },
    { question: "¿Optimizar arruinará las imágenes transparentes o los logotipos?", answer: "No. La herramienta detecta las imágenes con transparencia y las vuelve a codificar como PNG para conservar el canal alfa, mientras que las fotos opacas se comprimen como JPEG para obtener el máximo ahorro. Los logotipos y superposiciones transparentes mantienen sus zonas translúcidas intactas en lugar de adquirir un fondo sólido." },
    { question: "¿Qué pasa con los formatos de imagen que la herramienta no puede procesar?", answer: "Algunos formatos especializados, como ciertos flujos CMYK, JBIG2 o JPEG2000, no se pueden volver a codificar en el navegador. La herramienta simplemente omite esas imágenes y continúa optimizando el resto, por lo que el trabajo se completa correctamente en lugar de fallar con una imagen no compatible." },
    { question: "¿La optimización se realiza de forma privada en mi navegador?", answer: "Sí. Toda la reducción de escala y la compresión se ejecutan localmente en tu dispositivo, y no se sube nada a un servidor. Tu PDF permanece privado, lo que es ideal para reducir informes o presentaciones confidenciales antes de enviarlos por correo electrónico, todo de forma completamente gratuita." },
  ],
  "add-qr-code": [
    { question: "¿Qué puedo codificar en el código QR que añado?", answer: "Puedes codificar cualquier URL de un sitio web o texto sin formato, como un dato de contacto, un mensaje promocional o un enlace de descarga. Una vez escaneado, el código abre el enlace o muestra tu texto. Es útil para folletos, catálogos, facturas y entradas de eventos." },
    { question: "¿Puedo elegir dónde aparece el código QR en la página?", answer: "Sí. Tú estableces tanto la posición como el tamaño del código QR, de modo que quede exactamente donde quieras. También puedes apuntar a una página específica o a un rango de páginas en lugar de estamparlo en todo el documento." },
    { question: "¿El código QR seguirá escaneándose de forma fiable cuando se imprima?", answer: "Sí. El código se renderiza con nitidez a una alta resolución de píxeles y con corrección de errores integrada, por lo que se mantiene escaneable tanto en pantallas como en papel. Mantenerlo a un tamaño razonable en la página ayuda a que las cámaras lo detecten rápidamente." },
    { question: "¿Cómo añado un código QR a mi PDF?", answer: "Sube tu PDF, escribe la URL o el texto que quieras codificar y, luego, coloca y dimensiona el código en la página que elijas. La herramienta lo genera y lo coloca al instante, y descargas el PDF terminado de inmediato." },
    { question: "¿Mi PDF se mantiene privado al añadir un código QR?", answer: "Por supuesto. El código QR se genera e incrusta enteramente dentro de tu navegador, sin que ningún archivo salga nunca de tu dispositivo. Eso mantiene confidenciales las facturas, entradas y documentos internos, y la herramienta es gratuita y no requiere registro." },
  ],
  "add-barcode": [
    { question: "¿Qué formatos de código de barras admite esta herramienta?", answer: "Puedes generar Code128, Code39, EAN-13, UPC-A, ITF-14 e incluso códigos QR. Los formatos lineales son adecuados para el etiquetado minorista y de inventario, mientras que el QR funciona para enlaces o datos más extensos. Solo elige la simbología que coincida con tu escáner o flujo de trabajo." },
    { question: "¿La herramienta comprueba que los datos de mi código de barras son válidos?", answer: "Sí. Los formatos numéricos se validan antes de generarse, de modo que EAN-13 espera 12 o 13 dígitos, UPC-A necesita 11 o 12, e ITF-14 requiere 13 o 14. Si los datos no encajan con el formato elegido, obtendrás un error en lugar de un código no escaneable." },
    { question: "¿Puedo colocar el código de barras exactamente donde lo necesito en la página?", answer: "Tú controlas la posición, el ancho y el alto del código de barras, y puedes aplicarlo a una página específica o a un rango de páginas. Esto permite que el código se alinee con precisión con el diseño de tu etiqueta, etiqueta de precio u hoja de envío en lugar de quedar en un lugar fijo." },
    { question: "¿El código de barras se escaneará correctamente en la caja o el almacén?", answer: "Sí. Cada código de barras se renderiza a una resolución nítida y lista para imprimir, con el valor legible para humanos mostrado debajo. Esa salida nítida está diseñada para un escaneo fiable tanto en pantallas como en etiquetas impresas en las cajas registradoras y en las operaciones logísticas." },
    { question: "¿Añadir un código de barras es gratuito y privado?", answer: "Es gratuito y no se necesita cuenta, y el código de barras se crea directamente dentro de tu navegador. Tu PDF y los datos de tus productos nunca tocan un servidor, por lo que las hojas de inventario y los catálogos permanecen confidenciales mientras produces documentos escaneables internamente." },
  ],
  "add-bookmarks": [
    { question: "¿Cómo ayudan los marcadores a los lectores a navegar por mi PDF?", answer: "Los marcadores crean un esquema en el que se puede hacer clic y que aparece en la barra lateral de los lectores de PDF estándar. Los lectores hacen clic en una entrada para saltar directamente a esa página, lo que hace que los informes largos, los libros electrónicos y los manuales sean mucho más fáciles de recorrer que desplazándose página por página." },
    { question: "¿Puedo crear marcadores anidados o de varios niveles?", answer: "Sí. La herramienta admite marcadores jerárquicos, de modo que puedes anidar subentradas bajo los capítulos principales para construir una tabla de contenidos estructurada. Cada marcador apunta a una página específica, lo que le da a tu documento un árbol de navegación limpio y organizado en el panel del lector." },
    { question: "¿Puedo editar o reemplazar marcadores que ya existen?", answer: "Puedes añadir nuevas entradas y reconstruir el esquema del documento. De forma predeterminada, la herramienta reemplaza el esquema existente por la estructura que definas, lo que te permite reorganizar un conjunto de marcadores desordenado o desactualizado y convertirlo en uno nuevo y preciso para tus lectores." },
    { question: "¿Dónde aparecen los marcadores después de añadirlos?", answer: "Aparecen en la barra lateral de marcadores o esquema de cualquier visor de PDF estándar, incluidos Acrobat, Vista Previa y la mayoría de los navegadores. Los lectores abren ese panel para ver tu tabla de contenidos completa y hacer clic para acceder a cualquier sección al instante." },
    { question: "¿Mis archivos son privados cuando añado marcadores?", answer: "Sí. El esquema se escribe en tu PDF localmente en tu navegador, sin subirse a ningún servidor. Tu documento permanece en tu dispositivo todo el tiempo, y la herramienta es gratuita, sin registro ni marcas de agua." },
  ],
  "add-hyperlinks": [
    { question: "¿Qué tipos de enlaces puedo añadir a mi PDF?", answer: "Puedes añadir enlaces web en los que se puede hacer clic usando direcciones http o https, así como enlaces mailto para direcciones de correo electrónico. Los dominios sin más, como example.com, se actualizan automáticamente a una URL https completa, por lo que los lectores pueden tocar citas, referencias o datos de contacto directamente." },
    { question: "¿Puedo mostrar texto de enlace visible sobre el área enlazada?", answer: "Sí. Cada enlace puede incluir una etiqueta opcional que se dibuja dentro del rectángulo del enlace en azul, de modo que el área en la que se puede hacer clic sea claramente visible. Si dejas la etiqueta sin definir, el enlace sigue funcionando como una región invisible en la que se puede hacer clic sobre el contenido existente." },
    { question: "¿Cómo coloco un hipervínculo en la página?", answer: "Defines un área rectangular en una página específica donde se ubica el enlace, estableciendo su ubicación y tamaño en esa página. Esto te permite colocar una zona en la que se puede hacer clic con precisión sobre una palabra, una cita o una región en lugar de en toda la página." },
    { question: "¿Los enlaces seguirán siendo clicables en otros visores de PDF?", answer: "Sí. La herramienta añade anotaciones de enlace estándar, por lo que los enlaces siguen siendo totalmente interactivos en lectores comunes como Acrobat, Vista Previa y la mayoría de los navegadores. Los destinatarios pueden hacer clic en ellos para abrir la página web de destino o iniciar un correo electrónico sin pasos adicionales." },
    { question: "¿Se sube mi PDF cuando añado hipervínculos?", answer: "No. Los enlaces se incrustan localmente en tu navegador, y tu archivo nunca sale de tu dispositivo. Eso mantiene privados los informes y folletos ricos en referencias, y la herramienta es completamente gratuita, sin cuenta ni marca de agua en el documento terminado." },
  ],
  "add-attachments": [
    { question: "¿Qué tipos de archivos puedo incrustar en un PDF?", answer: "Puedes incrustar varios archivos de distintos tipos, como hojas de cálculo, imágenes, documentos y archivos de datos sin procesar. Viajan dentro del PDF como un solo paquete, lo que mantiene juntos los materiales relacionados para que nada se separe cuando compartes el documento." },
    { question: "¿Dónde aparecen los archivos adjuntos incrustados para el destinatario?", answer: "Se almacenan en el panel de archivos adjuntos del PDF, accesible en lectores estándar como Acrobat que admiten archivos incrustados. Los destinatarios abren ese panel para ver o guardar cada archivo adjunto. Las páginas visibles de tu documento no se modifican con la incrustación." },
    { question: "¿Incrustar archivos cambia el aspecto de las páginas de mi PDF?", answer: "No. Los archivos adjuntos se añaden a la estructura interna de archivos del documento, no se dibujan sobre las páginas, por lo que tu diseño, texto y formato permanecen exactamente como estaban. Los archivos adicionales viajan discretamente sin alterar nada de lo que los lectores ven en pantalla." },
    { question: "¿Por qué incrustar archivos en lugar de enviarlos por separado?", answer: "Agrupar todo en un solo PDF mantiene organizados los materiales relacionados y garantiza que los archivos de apoyo no se pierdan en el camino. Es útil para emparejar una hoja de cálculo con un informe financiero, adjuntar pruebas a un escrito legal o enviar datos de origen junto con un artículo de investigación." },
    { question: "¿Es gratuito y mis archivos se mantienen privados?", answer: "Sí en ambos casos. La incrustación ocurre localmente en tu navegador sin subirse a ningún servidor, por lo que los expedientes y conjuntos de datos confidenciales permanecen en tu dispositivo. La herramienta es gratuita, sin registro, inicio de sesión ni marcas de agua." },
  ],
};
